def greedy_decode(model, prompt_ids, max_tokens=256):
    tokens = list(prompt_ids)
    for _ in range(max_tokens):
        logits = model(tokens)[-1]
        next_id = int(logits.argmax())
        tokens.append(next_id)
        if next_id == EOS_ID:
            break
    return tokens

